B.aJL=s([B.uo,B.b4I,B.b4P,B.uq,B.b4Q,B.Pq,B.b4R,B.b4S,B.b4T,B.b4U,B.b4J,B.b4K,B.b4L,B.b4M,B.b4N,B.b4O,B.up],A.a7("p<ft>"))
B.aIV=s(["Vorher laut \xfcben und auf die Zeit achten.","Mit einem Satz enden, der zur ausgeschriebenen Stelle \xfcberleitet."],t.s)
B.a_v=new A.ef(B.lj,"Erz\xe4hlen Sie etwas \xfcber sich.","Ein 2\u20133-Minuten-Pitch in der Struktur Gegenwart \u2192 Vergangenheit \u2192 Zukunft: Wo stehst du, was hat dich dorthin gebracht, warum diese Stelle. Nur Berufsrelevantes, kein Lebenslauf zum Vorlesen.",B.aIV)
B.aMI=s(['Keine getarnte St\xe4rke (\u201eich bin zu perfektionistisch").',"H\xf6chstens zwei St\xe4rken, daf\xfcr mit Beleg."],t.s)
B.a_B=new A.ef(B.lj,"Was sind Ihre gr\xf6\xdften St\xe4rken und Schw\xe4chen?","St\xe4rken mit einem konkreten Beispiel (STAR) belegen, das zur Stelle passt. Bei der Schw\xe4che eine echte nennen \u2013 plus, wie du aktiv daran arbeitest.",B.aMI)
B.a_E=new A.ef(B.lj,"Warum sollten wir gerade Sie einstellen?","Die zwei, drei wichtigsten Anforderungen der Stelle aufgreifen und jeweils mit deiner Erfahrung matchen. Nutzen f\xfcr das Unternehmen in den Vordergrund stellen, nicht deine W\xfcnsche.",B.c8)
B.aM6=s(["Einen kurzen, ehrlichen Satz vorbereiten und ein\xfcben.","Schnell zum Ausblick wechseln: was du jetzt suchst."],t.s)
B.a_H=new A.ef(B.ll,"Warum haben Sie Ihre letzte Stelle verlassen?","Sachlich und knapp bleiben, nach vorn richten. Betriebsbedingte Gr\xfcnde (Umstrukturierung, Stellenabbau) neutral benennen. Nie \xfcber den alten Arbeitgeber schimpfen \u2013 das f\xe4llt auf dich zur\xfcck.",B.aM6)
B.aNM=s(["Kein Rechtfertigen \u2013 kurz erkl\xe4ren und weiter."],t.s)
B.a_C=new A.ef(B.ll,"Sie haben eine L\xfccke im Lebenslauf \u2013 wie kam es dazu?","Ehrlich und selbstbewusst: Was hast du in der Zeit getan (Weiterbildung, Bewerbungsphase, Pflege, Neuorientierung)? Zeig, dass die Zeit nicht verloren war.",B.aNM)
B.a_F=new A.ef(B.ll,"D\xfcrfen wir Ihren fr\xfcheren Arbeitgeber kontaktieren?","Ruhig bleiben. Du kannst auf ein qualifiziertes Zeugnis verweisen und um R\xfccksprache bitten, bevor Referenzen kontaktiert werden \u2013 das ist \xfcblich und legitim.",B.c8)
B.ayc=s(["Nenne die Zahl selbstbewusst, ohne dich sofort zu rechtfertigen.","Denk an das Gesamtpaket (Urlaub, Homeoffice, Weiterbildung, Bonus)."],t.s)
B.a_u=new A.ef(B.qC,"Was sind Ihre Gehaltsvorstellungen?","Vorher den Marktwert recherchieren (Branche, Region, Gr\xf6\xdfe). Eine Spanne oder einen konkreten Anker nennen, begr\xfcndet mit deiner Erfahrung und dem Verantwortungsumfang der Stelle.",B.ayc)
B.aOb=s(["Gehalt verhandelt sich am besten, wenn sie dich schon wollen."],t.s)
B.a_x=new A.ef(B.qC,"Ihre Forderung liegt \xfcber unserem Rahmen \u2013 warum so viel?","Auf Marktwert und den konkreten Nutzen verweisen, den du bringst. Gespr\xe4chsbereit bleiben, aber nicht sofort einknicken. Wenn kein Spielraum beim Gehalt ist: \xfcber andere Bausteine verhandeln.",B.aOb)
B.ao9=s(["Nicht defensiv werden \u2013 eine fehlende Anforderung ist selten ein K.-o."],t.s)
B.a_D=new A.ef(B.lk,"Sie passen bei Anforderung X nicht ganz.","Den Punkt ruhig anerkennen, nicht wegreden. Dann die n\xe4chste Erfahrung dagegenstellen und zeigen, wie schnell du dich einarbeitest \u2013 mit einem Beispiel, wo du dir Neues z\xfcgig angeeignet hast.",B.ao9)
B.a_y=new A.ef(B.lk,"Sie hatten noch nie disziplinarische F\xfchrungsverantwortung.","Fachliche F\xfchrung, Projekt- oder Teamleitung, Einarbeitung von Kollegen anf\xfchren. Lernbereitschaft zeigen und benennen, wie du in die Rolle hineinwachsen w\xfcrdest.",B.c8)
B.a_r=new A.ef(B.lk,"Ehrlich \u2013 Ihnen fehlt Erfahrung f\xfcr diese Rolle.",'Motivation und schnelle Einarbeitung betonen, Transfer aus anderen Bereichen zeigen und konkrete erste Erfolge (\u201eQuick Wins") skizzieren, die du fr\xfch liefern kannst. Value statt L\xfccke.',B.c8)
B.a_s=new A.ef(B.fb,"Was h\xe4lt Sie im Moment davon ab, mich einzustellen \u2013 wo sehen Sie blinde Flecken?","Die vielleicht st\xe4rkste Frage: Du erf\xe4hrst die echten Bedenken und kannst sie direkt ausr\xe4umen, statt dass sie unausgesprochen gegen dich wirken. Mutig, aber wirkungsvoll.",B.c8)
B.a_G=new A.ef(B.fb,"Was sind aktuell die gr\xf6\xdften Herausforderungen dieser Rolle?","Du positionierst dich sofort als L\xf6ser \u2013 und kannst deine Erfahrung genau auf ihren Schmerzpunkt zuschneiden.",B.c8)
B.a_w=new A.ef(B.fb,"Wer hatte die Stelle zuvor, was macht die Person heute, warum ist sie gegangen?","Deckt Fluktuation, Erwartungen und m\xf6gliche Probleme der Stelle auf \u2013 wichtige Infos f\xfcr deine Entscheidung und deine Verhandlung.",B.c8)
B.a_t=new A.ef(B.fb,"Wie s\xe4hen meine ersten Monate konkret aus?","Zeigt, dass du dich in die Rolle hineindenkst, und gibt dir ein realistisches Bild von Einarbeitung und Erwartungen.",B.c8)
B.a_A=new A.ef(B.fb,"Wie w\xfcrde f\xfcr Sie der perfekte Kandidat aussehen?","Lass sie das Wunschprofil beschreiben \u2013 dann hakst du im Gespr\xe4ch gezielt ab, was davon auf dich zutrifft.",B.c8)
B.aJ8=s(["Frag lieber nach den Umst\xe4nden, statt etwas anzunehmen \u2013 z. B. warum ein bestimmtes Startdatum wichtig ist. Oft ist mehr Spielraum als gedacht."],t.s)
B.a_z=new A.ef(B.fb,"Wie geht es dem Unternehmen bzw. dem Team gerade?","Signalisiert unternehmerisches Mitdenken. Frag ruhig konkret nach Wachstum, Umstrukturierungen oder der Auftragslage.",B.aJ8)
